import os, json, csv, re
from datetime import datetime
path = 'exp8_csv_small/csv/urban_air_quality_sensors_1_1.csv'
print("Inspecting file:", path)
try:
    with open(path, 'r', encoding='utf-8') as f:
        reader = csv.DictReader(f)
        fields = reader.fieldnames or []
        rows = list(reader)
except Exception as e:
    print("ERROR reading CSV:", e)
    raise

print("Columns detected:", fields)

# Detect PM2.5 column (handles pm2.5, pm25, pm_25 etc.)
pm_col = None
for f in fields:
    s = f.lower()
    s_clean = re.sub('[^a-z0-9]', '', s)
    if 'pm25' in s_clean:
        pm_col = f
        break
print("PM2.5 column detected:", pm_col)

# Detect potential timestamp/date column to derive diurnal hour
ts_col = None
for f in fields:
    if 'time' in f.lower() or 'date' in f.lower():
        ts_col = f
        break
print("Timestamp/date column detected:", ts_col)

# Detect a sensor identifier column (best-effort)
sensor_id_col = None
for f in fields:
    fl = f.lower()
    if 'sensor' in fl and ('id' in fl or 'name' in fl or 'code' in fl):
        sensor_id_col = f
        break
print("Sensor ID column detected:", sensor_id_col)

# Gather rows with usable data
def parse_float(v):
    try:
        return float(v)
    except:
        return None

hours = []
pm_vals = []
sensor_ids = set()
for r in rows:
    if pm_col is None:
        continue
    pv = r.get(pm_col)
    pm = parse_float(pv)
    if pm is None:
        continue

    # Determine hour
    hour = None
    if ts_col:
        ts = r.get(ts_col)
        if ts:
            try:
                dt = None
                try:
                    dt = datetime.fromisoformat(ts)
                except:
                    for fmt in ("%Y-%m-%d %H:%M:%S","%Y-%m-%d %H:%M","%Y-%m-%d"):
                        try:
                            dt = datetime.strptime(ts, fmt)
                            break
                        except:
                            continue
                if dt:
                    hour = dt.hour
            except Exception:
                pass
    if hour is None:
        # Fallback: look for an explicit hour column
        for f in fields:
            if f.lower() in ('hour', 'hour_of_day'):
                val = r.get(f)
                if val is not None:
                    try:
                        hour = int(val)
                    except:
                        hour = None
                break
    if hour is None:
        hour = 0

    hours.append(hour)
    pm_vals.append(pm)
    if sensor_id_col:
        sid = r.get(sensor_id_col)
        if sid is not None:
            sensor_ids.add(sid)

# Compute hourly means (diurnal pattern)
hour_means = {}
for h, p in zip(hours, pm_vals):
    hour_means.setdefault(h, []).append(p)
hourly_mean = {h: sum(v)/len(v) for h, v in hour_means.items() if v}
amplitude = None
if hourly_mean:
    amplitude = max(hourly_mean.values()) - min(hourly_mean.values())

# Detect anomalies: residuals vs diurnal mean, flag when > 1.5 * stddev
import statistics
anomalies = []
if pm_vals and hours and hourly_mean:
    residuals = []
    for h, p in zip(hours, pm_vals):
        mean = hourly_mean.get(h, None)
        if mean is None:
            mean = sum(hourly_mean.values())/len(hourly_mean) if hourly_mean else p
        res = p - mean
        residuals.append(res)
    stdev = statistics.pstdev(residuals) if len(residuals) > 1 else 0.0
    for (h, p, res) in zip(hours, pm_vals, residuals):
        if stdev > 0 and abs(res) > 1.5 * stdev:
            anomalies.append((h, p, res))
anomaly_count = len(anomalies)
total_rows = len(rows)
anomaly_rate = anomaly_count / total_rows if total_rows else 0
max_abs_residual = max((abs(res) for (_,_,res) in anomalies), default=0.0)

print("Diurnal fluctuation metric: hourly PM2.5 mean amplitude =", amplitude)
print("Total rows in file =", total_rows)
print("Estimated unique sensors =", len(sensor_ids) if sensor_ids else 1)

print("Anomaly count =", anomaly_count)
print("Anomaly rate (proportion of rows) =", anomaly_rate)
print("Largest absolute anomaly magnitude (PM2.5 units) =", max_abs_residual)

# Show hyper-parameter JSONs if present in folder
dirpath = os.path.dirname(path)
print("Scanning for JSON files in directory:", dirpath)
try:
    for fname in os.listdir(dirpath):
        if not fname.lower().endswith('.json'):
            continue
        full = os.path.join(dirpath, fname)
        with open(full, 'r', encoding='utf-8') as jf:
            data = json.load(jf)
        if 'params' in fname.lower() or 'param' in fname.lower():
            print("PARAMS JSON file found:", fname)
            print("Param keys and values:")
            for k, v in (data.items() if isinstance(data, dict) else []):
                print("  {}: {}".format(k, v))
        elif 'payload' in fname.lower():
            print("PAYLOAD JSON file found:", fname)
            print("Payload keys and values:")
            for k, v in (data.items() if isinstance(data, dict) else []):
                print("  {}: {}".format(k, v))
        else:
            # Print a brief summary if JSON has recognizable keys
            if isinstance(data, dict):
                print("JSON file:", fname, "keys:", list(data.keys())[:5])
except Exception as e:
    print("JSON scanning error:", e)

# Try to surface hyper-parameter naming if present
hyper_param_index = None
total_hyper_params = None
for fname in os.listdir(dirpath) if os.path.isdir(dirpath) else []:
    if not fname.lower().endswith('.json'):
        continue
    try:
        with open(os.path.join(dirpath, fname), 'r', encoding='utf-8') as jf:
            j = json.load(jf)
        if isinstance(j, dict):
            if 'hyper_param_index' in j:
                hyper_param_index = j['hyper_param_index']
            if 'total_hyper_params' in j:
                total_hyper_params = j['total_hyper_params']
    except:
        pass
if hyper_param_index is not None or total_hyper_params is not None:
    print("Hyper-parameter indexing detected: hyper_param_index =", hyper_param_index, ", total_hyper_params =", total_hyper_params)
else:
    print("Hyper-parameter indexing not explicitly detected in JSON files.")
