import csv, json
path = 'exp8_csv_small/csv/renewable_energy_output_1_1.csv'
try:
    with open(path, newline='') as f:
        reader = csv.DictReader(f)
        rows = list(reader)
except FileNotFoundError:
    print("Could not find file:", path)
    raise SystemExit(1)

def get(r, keys, default=None):
    for k in keys:
        if k in r and r[k] != '':
            return r[k]
    return default

# Gather run-level params
hyper_idx = get(rows[0], ['hyper_param_index'])
season = None; seasonality_amplitude=None; anomaly_probability=None
solar_panel_efficiency=None; wind_base_multiplier=None
for r in rows:
    if season is None:
        season = get(r, ['season'], None)
    if seasonality_amplitude is None:
