    if anomaly_probability is None:
        anomaly_probability = get(r, ['anomaly_probability'], None)
    if solar_panel_efficiency is None:
        solar_panel_efficiency = get(r, ['solar_panel_efficiency'], None)
    if wind_base_multiplier is None:
        wind_base_multiplier = get(r, ['wind_base_multiplier'], None)
    if hyper_idx is None:
        hyper_idx = get(r, ['hyper_param_index'], None)

# Build hourly data
hours = []
for r in rows:
    h = get(r, ['hour','time','t'], None)
    try:
        hour = int(h) if h is not None else None
    except:
        hour = None
    sc = None
    for k in ('solar_contribution','solar','solar_contrib','diurnal_solar'):
        if k in r and r[k] != '':
            try:
                sc = float(r[k])
            except:
                sc = None
            break
    payload = r.get('payload_json','')
    payload_obj = None
    if payload:
        try:
            payload_obj = json.loads(payload)
        except Exception:
            payload_obj = None
    hours.append({'hour':hour,'sc':sc,'payload':payload_obj})

valid = [h for h in hours if h['hour'] is not None and h['sc'] is not None]
if not valid:
    print("No valid hourly solar contribution data found.")
else:
    max_entry = max(valid, key=lambda x: x['sc'])
    max_hour = max_entry['hour']; max_sc = max_entry['sc']
    avg_sc = sum(h['sc'] for h in valid)/len(valid)
    def has_anomaly(p):
        if not isinstance(p, dict):
            return False
        if p.get('anomaly') is True:
            return True
        if p.get('anomalies') and isinstance(p['anomalies'], list) and len(p['anomalies'])>0:
            return True
        if p.get('error') is not None:
            return True
        if p.get('fault') is not None:
            return True
        return False
    anomaly_count = sum(1 for h in hours if has_anomaly(h['payload']))
    anomaly_examples = [h['payload'] for h in hours if has_anomaly(h['payload'])][:3]

    print("Hyper-parameter index for this run: ", hyper_idx if hyper_idx is not None else 'unknown')
    print("Selected hyper-parameters:")
    if season is not None:
        print(" - season:", season)
    if seasonality_amplitude is not None:
        print(" - seasonality_amplitude:", seasonality_amplitude)
    if anomaly_probability is not None:
        print(" - anomaly_probability:", anomaly_probability)
    if solar_panel_efficiency is not None:
        print(" - solar_panel_efficiency:", solar_panel_efficiency)
    if wind_base_multiplier is not None:
        print(" - wind_base_multiplier:", wind_base_multiplier)

    print("Diurnal solar contribution (24 hours):")
    print(" - average across 24 hours:", round(avg_sc, 4))
    print(" - peak occurs at hour", max_hour, "with value", round(max_sc,4))

    print("Observed anomalies across hours:")
    print(" - total anomaly events:", anomaly_count)
    if anomaly_count > 0:
        print(" - sample anomalous payloads (first few):")
        for a in anomaly_examples[:3]:
            print("   -", a)
    if anomaly_probability:
        try:
            ap = float(anomaly_probability)
            expected = ap * 24
            print("Expected anomalies (based on anomaly_probability) over 24 hours:", round(expected, 2))
        except:
            pass
